var progress = new Progress<long>(bytes => 
    Console.WriteLine($"已上传: {bytes} 字节"));

using var fileContent = new StreamContent(File.OpenRead("largefile.zip"));
using var progressContent = new ProgressableStreamContent(fileContent, progress);

var response = await httpClient.PostAsync("/upload", progressContent);

member.example:
使用示例：

var masker = new DefaultSensitiveDataMasker();

// 字符串掩码
var masked = masker.Mask("1234567890", SensitiveDataMaskMode.Mask, 2, 2);
// 输出: "12***90"

// 对象掩码（属性标记了 [SensitiveData] 的会被自动掩码）
var user = new { Username = "john", Password = "secret123" };
var maskedObj = masker.MaskObject(user);
// 输出: JSON 格式，其中标记为敏感的字段会被掩码处理

