使用示例：

// 获取默认 API Key
var defaultKey = await provider.GetApiKeyAsync();

// 获取命名 API Key
var serviceAKey = await provider.GetApiKeyAsync("ServiceA");

使用示例：

var provider = new DefaultHmacSignatureProvider();

// 生成签名
var signature = await provider.GenerateSignatureAsync(request, secretKey);

// 验证签名
var isValid = await provider.VerifySignatureAsync(request, signature, secretKey);

member.remarks:
配置格式示例（appsettings.json）：

{
  "MudHttpClients": {
    "DefaultClientName": "user-api",
    "Clients": {
      "user-api": {
        "BaseAddress": "https://user-api.example.com",
        "TimeoutSeconds": 30,
        "DefaultHeaders": { "X-Api-Version": "v1" },
        "TokenManagerKey": "user-api-token",
        "TokenInjectionMode": "Header",
        "TokenScopes": "user.read user.write"
      },
      "order-api": {
        "BaseAddress": "https://order-api.example.com",
        "TimeoutSeconds": 60,
        "TokenManagerKey": "order-api-token"
      }
    }
  }
}

example.code:
// 注册到依赖注入容器
services.AddSingleton<IEncryptionProvider, AesEncryptionProvider>();
services.AddSingleton<IEncryptedTokenStore, MemoryEncryptedTokenStore>();

// 使用存储（加密/解密完全透明）
var store = serviceProvider.GetRequiredService<IEncryptedTokenStore>();
await store.SetAccessTokenAsync("TenantAccessToken", "sensitive_token", 3600);
var token = await store.GetAccessTokenAsync("TenantAccessToken"); // 自动解密返回

// 注册到依赖注入容器
services.AddSingleton<ITokenStore, MemoryTokenStore>();

// 使用存储
var store = serviceProvider.GetRequiredService<ITokenStore>();
await store.SetAccessTokenAsync("TenantAccessToken", "access_token_value", 3600);
var token = await store.GetAccessTokenAsync("TenantAccessToken");

// 注册到依赖注入容器
services.AddSingleton<IUserTokenStore, MemoryUserTokenStore>();

// 使用存储
var store = serviceProvider.GetRequiredService<IUserTokenStore>();
await store.SetAccessTokenAsync("user123", "UserAccessToken", "access_token", 3600);
var token = await store.GetAccessTokenAsync("user123", "UserAccessToken");

// 在注册 HttpClient 时添加令牌恢复处理器
services.AddHttpClient("MyApi")
    .AddHttpMessageHandler<TokenRecoveryDelegatingHandler>();

// 在 Program.cs 或 Startup.cs 中注册服务
builder.Services.AddTokenRefreshBackgroundService(options =>
{
    options.Enabled = true;
    options.RefreshIntervalSeconds = 300; // 5分钟
    options.RetryDelaySeconds = 30;
    options.StopOnError = false;
});
